import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { combineLatest, map } from 'rxjs';
import { ThemeCardComponent } from '../../../components/card/theme-card/theme-card.component';
import { ThemeService } from '../../../core/services/theme.service';

@Component({
  selector: 'app-theme',
  imports: [AsyncPipe, ThemeCardComponent],
  templateUrl: './theme.component.html',
  styleUrl: './theme.component.scss',
})
export class ThemeComponent {
  private themeService = inject(ThemeService);
  private destroyRef = inject(DestroyRef);
  allThemes$ = this.themeService.getAllThemes();
  subscribedThemes$ = this.themeService.getUserSubscriptions();

  // add subscription state to themes before injecting them into the cards
  themes$ = combineLatest([this.allThemes$, this.subscribedThemes$]).pipe(
    takeUntilDestroyed(this.destroyRef),
    map(
      ([allThemes, subscribedThemes]) => {
        const subscribedThemesIds = new Set(subscribedThemes.map(s => s.id))
        return allThemes.map(theme => ({
          ...theme,
          isSubscribed: subscribedThemesIds.has(theme.id)
        }))
      }
    )
  )
}

import { Routes } from '@angular/router';
import { LoginComponent } from './features/auth/login.component/login.component';
import { RegisterComponent } from './features/auth/register.component/register.component';
import { HomeComponent } from './features/home/home.component';
import { ArticleCreationComponent } from './features/main/article/article-creation/article-creation.component';
import { ArticleDetailsComponent } from './features/main/article/article-details/article-details.component';
import { ArticleComponent } from './features/main/article/article.component';
import { MeComponent } from './features/main/me/me.component';
import { ThemeComponent } from './features/main/theme/theme.component';

export const routes: Routes = [
    {
        path: '', component: HomeComponent,
        children: [
            { path: '', redirectTo: 'articles', pathMatch: 'full' },
            { path: 'articles', component: ArticleComponent },
            { path: 'themes', component: ThemeComponent },
            { path: 'me', component: MeComponent },
            { path: 'articles/new', component: ArticleCreationComponent },
            { path: 'articles/:id', component: ArticleDetailsComponent }
        ]
    },
    { path: 'register', component: RegisterComponent },
    { path: 'login', component: LoginComponent },

];

import { HttpEvent, HttpHandlerFn, HttpInterceptorFn, HttpRequest } from "@angular/common/http";
import { Observable } from "rxjs";

export const tokenInterceptor: HttpInterceptorFn = (req: HttpRequest<unknown>, next: HttpHandlerFn): Observable<HttpEvent<unknown>> => {
    if (req.url.includes('/login') || req.url.includes('/register')) {
        return next(req);
    }

    const tokenKey = "MDD_token";
    const authReq = req.clone({
        setHeaders: {
            Authorization: `Bearer ${localStorage.getItem(tokenKey)}`
        }
    })
    return next(authReq)
}

import { ApplicationConfig, provideBrowserGlobalErrorListeners } from '@angular/core';
import { provideRouter, withComponentInputBinding } from '@angular/router';

import { provideHttpClient, withInterceptors } from '@angular/common/http';
import { routes } from './app.routes';
import { tokenInterceptor } from './core/interceptors/token.interceptor';

export const appConfig: ApplicationConfig = {
  providers: [
    provideBrowserGlobalErrorListeners(),
    provideRouter(routes, withComponentInputBinding()),
    provideHttpClient(
      withInterceptors([tokenInterceptor])
    )
  ]
};

import { Component, signal } from '@angular/core';
